import { addNews } from '../db'
import MAIN from '../Main/Main'
import Post from '../../Post'

import "./Account.css"

export default class Account extends Component {
    
    render() {
        // let PostList = Post
        // for (let i = 10; i < Object.keys(Post).length; i++) {
        // }
        return (
            <div>
                <div className={Object.keys(Post.num15) ? "user-posts" : "d-none"}>
                    <div className="title-crea">Посты созданые вами:</div>
                    <MAIN list={Post} userPosts={true} listVisible={""}/>
                </div>
                <div className="user-posts">
                    <div className="title-crea">Посты понравившиеся вами:</div>
                    <MAIN list={Post} userPosts={true} listVisible={""}/>
                </div>
            </div>
        )
    }
}
